/**
 * Generated by `createservice subscription.RegisterSubscriptionContextService --type mutations`
 */

const { faker } = require('@faker-js/faker')
const dayjs = require('dayjs')

const { makeLoggedInAdminClient, makeClient, expectToThrowGQLError } = require('@open-condo/keystone/test.utils')
const { expectToThrowAccessDeniedErrorToResult, expectToThrowAuthenticationErrorToResult } = require('@open-condo/keystone/test.utils')

const { CONTEXT_FINISHED_STATUS } = require('@condo/domains/acquiring/constants/context')
const {
    createTestAcquiringIntegration,
    createTestAcquiringIntegrationContext,
    AcquiringIntegration,
    AcquiringIntegrationContext,
} = require('@condo/domains/acquiring/utils/testSchema')
const { createTestRecipient } = require('@condo/domains/billing/utils/testSchema')
const { HOLDING_TYPE, MANAGING_COMPANY_TYPE, SERVICE_PROVIDER_TYPE } = require('@condo/domains/organization/constants/common')
const { registerNewOrganization, Organization } = require('@condo/domains/organization/utils/testSchema')
const { SUBSCRIPTION_PERIOD, SUBSCRIPTION_CONTEXT_STATUS } = require('@condo/domains/subscription/constants')
const {
    registerSubscriptionContextByTestClient,
    createTestSubscriptionPlan,
    createTestSubscriptionPlanPricingRule,
    createTestSubscriptionContext,
} = require('@condo/domains/subscription/utils/testSchema')
const { makeClientWithNewRegisteredAndLoggedInUser, makeClientWithSupportUser } = require('@condo/domains/user/utils/testSchema')

const { ERRORS } = require('./RegisterSubscriptionContextService')

describe('RegisterSubscriptionContextService', () => {
    let admin, support, user, anonymous
    let organization, subscriptionPlan, pricingRule

    beforeAll(async () => {
        admin = await makeLoggedInAdminClient()
        support = await makeClientWithSupportUser()
        anonymous = await makeClient()

        const recipientOrganizationId = process.env.SUBSCRIPTION_PAYMENT_RECIPIENT
        if (!recipientOrganizationId) {
            throw new Error('SUBSCRIPTION_PAYMENT_RECIPIENT is not configured. Run yarn prepare first.')
        }

        const existingIntegrations = await AcquiringIntegration.getAll(admin, {})
        let acquiringIntegration
        if (existingIntegrations.length > 0) {
            acquiringIntegration = existingIntegrations[0]
        } else {
            const [integration] = await createTestAcquiringIntegration(admin)
            acquiringIntegration = integration
        }

        const existingContexts = await AcquiringIntegrationContext.getAll(admin, {
            organization: { id: recipientOrganizationId },
        })

        if (existingContexts.length === 0) {
            const recipientOrg = await Organization.getOne(admin, { id: recipientOrganizationId })

            await createTestAcquiringIntegrationContext(admin, recipientOrg, acquiringIntegration, {
                invoiceStatus: CONTEXT_FINISHED_STATUS,
                invoiceRecipient: createTestRecipient(),
                invoiceImplicitFeeDistributionSchema: [],
            })
        }

        const [plan] = await createTestSubscriptionPlan(admin, {
            name: faker.commerce.productName(),
            organizationType: MANAGING_COMPANY_TYPE,
            isHidden: false,
            trialDays: 14,
        })
        subscriptionPlan = plan

        const [rule] = await createTestSubscriptionPlanPricingRule(admin, subscriptionPlan, {
            period: SUBSCRIPTION_PERIOD.MONTH,
            price: '1000.00',
            currencyCode: 'RUB',
        })
        pricingRule = rule
    })

    beforeEach(async () => {
        user = await makeClientWithNewRegisteredAndLoggedInUser()
        const [org] = await registerNewOrganization(user, { type: MANAGING_COMPANY_TYPE })
        organization = org
    })

    describe('Access', () => {
        test('admin can register trial subscription', async () => {
            const [result] = await registerSubscriptionContextByTestClient(admin, {
                organization: { id: organization.id },
                subscriptionPlanPricingRule: { id: pricingRule.id },
                isTrial: true,
            })

            expect(result.subscriptionContext).toBeDefined()
            expect(result.subscriptionContext.isTrial).toBe(true)
        })

        test('support can register trial subscription', async () => {
            const [result] = await registerSubscriptionContextByTestClient(support, {
                organization: { id: organization.id },
                subscriptionPlanPricingRule: { id: pricingRule.id },
                isTrial: true,
            })

            expect(result.subscriptionContext).toBeDefined()
            expect(result.subscriptionContext.isTrial).toBe(true)
        })

        test('organization admin can register trial for own organization', async () => {
            const [result] = await registerSubscriptionContextByTestClient(user, {
                organization: { id: organization.id },
                subscriptionPlanPricingRule: { id: pricingRule.id },
                isTrial: true,
            })

            expect(result.subscriptionContext).toBeDefined()
            expect(result.subscriptionContext.isTrial).toBe(true)
        })

        test('user cannot register for other organization', async () => {
            const otherUser = await makeClientWithNewRegisteredAndLoggedInUser()
            const [otherOrg] = await registerNewOrganization(otherUser, { type: MANAGING_COMPANY_TYPE })

            await expectToThrowAccessDeniedErrorToResult(async () => {
                await registerSubscriptionContextByTestClient(user, {
                    organization: { id: otherOrg.id },
                    subscriptionPlanPricingRule: { id: pricingRule.id },
                    isTrial: true,
                })
            })
        })

        test('anonymous cannot register', async () => {
            await expectToThrowAuthenticationErrorToResult(async () => {
                await registerSubscriptionContextByTestClient(anonymous, {
                    organization: { id: organization.id },
                    subscriptionPlanPricingRule: { id: pricingRule.id },
                    isTrial: true,
                })
            })
        })
    })

    describe('Trial Logic', () => {
        test('creates trial subscription context with status DONE and correct dates', async () => {
            const [result] = await registerSubscriptionContextByTestClient(user, {
                organization: { id: organization.id },
                subscriptionPlanPricingRule: { id: pricingRule.id },
                isTrial: true,
            })

            const context = result.subscriptionContext
            expect(context.isTrial).toBe(true)
            expect(context.status).toBe(SUBSCRIPTION_CONTEXT_STATUS.DONE)
            expect(context.organization.id).toBe(organization.id)
            expect(context.subscriptionPlan.id).toBe(subscriptionPlan.id)

            const startAt = dayjs(context.startAt)
            const endAt = dayjs(context.endAt)
            expect(endAt.diff(startAt, 'day')).toBe(subscriptionPlan.trialDays)

            expect(result.directPaymentUrl).toBeNull()
            expect(result.multiPayment).toBeNull()
        })

        test('throws error if trial is not available (trialDays = 0)', async () => {
            const [noTrialPlan] = await createTestSubscriptionPlan(admin, {
                name: faker.commerce.productName(),
                organizationType: MANAGING_COMPANY_TYPE,
                isHidden: false,
                trialDays: 0,
            })
            const [noTrialRule] = await createTestSubscriptionPlanPricingRule(admin, noTrialPlan, {
                period: SUBSCRIPTION_PERIOD.MONTH,
                price: '1000.00',
                currencyCode: 'RUB',
            })

            await expectToThrowGQLError(async () => {
                await registerSubscriptionContextByTestClient(user, {
                    organization: { id: organization.id },
                    subscriptionPlanPricingRule: { id: noTrialRule.id },
                    isTrial: true,
                })
            }, ERRORS.TRIAL_NOT_AVAILABLE, 'result')
        })

        test('throws error if trial already used', async () => {
            await registerSubscriptionContextByTestClient(user, {
                organization: { id: organization.id },
                subscriptionPlanPricingRule: { id: pricingRule.id },
                isTrial: true,
            })

            await expectToThrowGQLError(async () => {
                await registerSubscriptionContextByTestClient(user, {
                    organization: { id: organization.id },
                    subscriptionPlanPricingRule: { id: pricingRule.id },
                    isTrial: true,
                })
            }, ERRORS.TRIAL_ALREADY_USED, 'result')
        })
    })

    describe('Paid Subscription', () => {
        test('creates subscription context with status CREATED, multiPayment, and directPaymentUrl', async () => {
            const [result] = await registerSubscriptionContextByTestClient(user, {
                organization: { id: organization.id },
                subscriptionPlanPricingRule: { id: pricingRule.id },
                isTrial: false,
            })

            expect(result.subscriptionContext).toBeDefined()
            expect(result.subscriptionContext.status).toBe(SUBSCRIPTION_CONTEXT_STATUS.CREATED)
            expect(result.subscriptionContext.isTrial).toBe(false)
            expect(result.subscriptionContext.invoice).toBeDefined()
            expect(result.subscriptionContext.organization.id).toBe(organization.id)
            expect(result.subscriptionContext.subscriptionPlan.id).toBe(subscriptionPlan.id)
            expect(result.subscriptionContext.subscriptionPlanPricingRule.id).toBe(pricingRule.id)

            expect(result.multiPayment).toBeDefined()
            expect(result.directPaymentUrl).toBeDefined()
            expect(typeof result.directPaymentUrl).toBe('string')
        })

        test('calculates correct subscription dates based on pricing rule period', async () => {
            const [yearlyRule] = await createTestSubscriptionPlanPricingRule(admin, subscriptionPlan, {
                period: SUBSCRIPTION_PERIOD.YEAR,
                price: '10000.00',
                currencyCode: 'RUB',
            })

            const [result] = await registerSubscriptionContextByTestClient(user, {
                organization: { id: organization.id },
                subscriptionPlanPricingRule: { id: yearlyRule.id },
                isTrial: false,
            })

            const context = result.subscriptionContext
            const startAt = dayjs(context.startAt)
            const endAt = dayjs(context.endAt)
            expect(endAt.diff(startAt, 'month')).toBe(12)
        })

        test('extends subscription from last active context end date', async () => {
            const existingEndAt = dayjs().add(30, 'days')
            await createTestSubscriptionContext(admin, organization, subscriptionPlan, {
                startAt: dayjs().format('YYYY-MM-DD'),
                endAt: existingEndAt.format('YYYY-MM-DD'),
                isTrial: false,
                status: SUBSCRIPTION_CONTEXT_STATUS.DONE,
            })

            const [result] = await registerSubscriptionContextByTestClient(user, {
                organization: { id: organization.id },
                subscriptionPlanPricingRule: { id: pricingRule.id },
                isTrial: false,
            })

            const context = result.subscriptionContext
            const startAt = dayjs(context.startAt)
            expect(startAt.format('YYYY-MM-DD')).toBe(existingEndAt.format('YYYY-MM-DD'))
        })

        test('only considers DONE status contexts when calculating start date', async () => {
            const existingDoneEndDate = dayjs().add(10, 'day')
            await createTestSubscriptionContext(admin, organization, subscriptionPlan, {
                startAt: dayjs().format('YYYY-MM-DD'),
                endAt: existingDoneEndDate.format('YYYY-MM-DD'),
                status: SUBSCRIPTION_CONTEXT_STATUS.DONE,
                isTrial: false,
            })

            await createTestSubscriptionContext(admin, organization, subscriptionPlan, {
                startAt: existingDoneEndDate.format('YYYY-MM-DD'),
                endAt: dayjs().add(40, 'day').format('YYYY-MM-DD'),
                status: SUBSCRIPTION_CONTEXT_STATUS.CREATED,
                isTrial: false,
            })

            const [result] = await registerSubscriptionContextByTestClient(user, {
                organization: { id: organization.id },
                subscriptionPlanPricingRule: { id: pricingRule.id },
                isTrial: false,
            })

            const context = result.subscriptionContext
            const startAt = dayjs(context.startAt)
            expect(startAt.format('YYYY-MM-DD')).toBe(existingDoneEndDate.format('YYYY-MM-DD'))
        })
    })

    describe('Validation', () => {
        test('throws error if organization not found', async () => {
            const fakeOrg = { id: '00000000-0000-0000-0000-000000000000' }

            await expectToThrowAccessDeniedErrorToResult(async () => {
                await registerSubscriptionContextByTestClient(user, {
                    organization: fakeOrg,
                    subscriptionPlanPricingRule: { id: pricingRule.id },
                    isTrial: true,
                })
            })
        })

        test('throws error if pricing rule not found', async () => {
            const fakeRule = { id: '00000000-0000-0000-0000-000000000000' }

            await expectToThrowGQLError(async () => {
                await registerSubscriptionContextByTestClient(user, {
                    organization: { id: organization.id },
                    subscriptionPlanPricingRule: fakeRule,
                    isTrial: true,
                })
            }, ERRORS.PRICING_RULE_NOT_FOUND, 'result')
        })

        test('throws error if plan is hidden', async () => {
            const [hiddenPlan] = await createTestSubscriptionPlan(admin, {
                name: faker.commerce.productName(),
                organizationType: MANAGING_COMPANY_TYPE,
                isHidden: true,
                trialDays: 14,
            })
            const [hiddenPlanRule] = await createTestSubscriptionPlanPricingRule(admin, hiddenPlan, {
                period: SUBSCRIPTION_PERIOD.MONTH,
                price: '1000.00',
                currencyCode: 'RUB',
            })

            await expectToThrowGQLError(async () => {
                await registerSubscriptionContextByTestClient(user, {
                    organization: { id: organization.id },
                    subscriptionPlanPricingRule: { id: hiddenPlanRule.id },
                    isTrial: true,
                })
            }, ERRORS.PRICING_RULE_NOT_FOUND, 'result')
        })

        test('throws error if organization type does not match plan', async () => {
            const [servicePlan] = await createTestSubscriptionPlan(admin, {
                name: faker.commerce.productName(),
                organizationType: 'SERVICE_PROVIDER',
                isHidden: false,
                trialDays: 14,
            })
            const [servicePlanRule] = await createTestSubscriptionPlanPricingRule(admin, servicePlan, {
                period: SUBSCRIPTION_PERIOD.MONTH,
                price: '1000.00',
                currencyCode: 'RUB',
            })

            await expectToThrowGQLError(async () => {
                await registerSubscriptionContextByTestClient(user, {
                    organization: { id: organization.id },
                    subscriptionPlanPricingRule: { id: servicePlanRule.id },
                    isTrial: true,
                })
            }, ERRORS.INVALID_ORGANIZATION_TYPE, 'result')
        })
    })
})